   136→/**
   137→ * Dashboard Page - Personal overview
   138→ */
   139→export const Dashboard: React.FC = () => {
   140→  const [hasData, setHasData] = useState(true);
   141→  const [showBackupReminder, setShowBackupReminder] = useState(false);
   142→  const [showWidgetManager, setShowWidgetManager] = useState(false);
   143→  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
   144→  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
   145→  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);
   146→
   147→  // Configure drag sensors (require 5px movement to prevent accidental drags)
   148→  const sensors = useSensors(
   149→    useSensor(PointerSensor, {
   150→      activationConstraint: {
   151→        distance: 5,
   152→      },
   153→    })
   154→  );
   155→
   156→  // Handle drag end - reorder widgets
   157→  const handleDragEnd = (event: DragEndEvent) => {
   158→    const { active, over } = event;
   159→
   160→    if (over && active.id !== over.id) {
   161→      const oldIndex = enabledWidgets.indexOf(active.id as string);
   162→      const newIndex = enabledWidgets.indexOf(over.id as string);
   163→
   164→      if (oldIndex !== -1 && newIndex !== -1) {
   165→        const newOrder = [...enabledWidgets];
   166→        const [movedItem] = newOrder.splice(oldIndex, 1);
   167→        newOrder.splice(newIndex, 0, movedItem);
   168→        reorderWidgets(newOrder);
   169→      }
   170→    }
   171→  };
   172→
   173→  useEffect(() => {
   174→    document.title = 'Neuman Brain';
   175→
   176→    // Check for hash navigation (#customize-widgets)
   177→    if (window.location.hash === '#customize-widgets') {
   178→      setShowWidgetManager(true);
   179→      // Clear the hash
   180→      window.history.replaceState(null, '', window.location.pathname);
   181→    }
   182→
   183→    // Check if user has any data
   184→    const checkForData = async () => {
   185→      try {
   186→        const keys = await indexedDBService.getAllKeys();
   187→        const hasAnyData = keys.length > 0;
   188→        setHasData(hasAnyData);
   189→
   190→        // Show backup reminder if no data AND not dismissed
   191→        const dismissed = localStorage.getItem('dashboard-backup-reminder-dismissed');
   192→        if (!hasAnyData && !dismissed) {
   193→          setShowBackupReminder(true);
   194→        }
   195→      } catch (error) {
   196→        console.error('Failed to check for data:', error);
   197→      }
   198→    };
   199→
   200→    checkForData();
   201→  }, []);
   202→
   203→  const handleDismissReminder = () => {
   204→    setShowBackupReminder(false);
   205→    localStorage.setItem('dashboard-backup-reminder-dismissed', 'true');
   206→  };
   207→
   208→  return (
   209→    <div className="dashboard-page">
   210→      <div className="mb-8">
   211→        <h1 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   212→          Dashboard
   213→        </h1>
   214→        <p className="text-base text-text-light-secondary dark:text-text-dark-secondary">
   215→          Your personal management overview
   216→        </p>
   217→      </div>
   218→
   219→      {/* First-Time User Backup Reminder */}
   220→      {showBackupReminder && !hasData && (
   221→        <div className="mb-6 p-6 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-400 dark:border-yellow-600">
   222→          <div className="flex items-start gap-4">
   223→            <span className="text-3xl">⚠️</span>
   224→            <div className="flex-1">
   225→              <h3 className="text-xl font-bold text-yellow-900 dark:text-yellow-300 mb-2">
   226→                Welcome to Neuman Brain!
   227→              </h3>
   228→              <p className="text-sm text-yellow-800 dark:text-yellow-400 mb-3">
   229→                <strong>Important:</strong> Your data is stored locally in this browser. To protect your work, remember to create regular backups!
   230→              </p>
   231→              <div className="bg-white dark:bg-surface-dark-elevated p-4 rounded-lg mb-4">
   232→                <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   233→                  Quick Start:
   234→                </p>
   235→                <ol className="text-sm text-text-light-secondary dark:text-text-dark-secondary space-y-1 list-decimal list-inside ml-2">
   236→                  <li>Start creating tasks, notes, and plans</li>
   237→                  <li>When you have data to protect, go to Settings → Backup</li>
   238→                  <li>Export your first backup (Chrome/Edge: enable Auto-Save!)</li>
   239→                  <li>Store your .brain file somewhere safe (cloud, USB, etc.)</li>
   240→                </ol>
   241→              </div>
   242→              <button
   243→                onClick={handleDismissReminder}
   244→                className="px-4 py-2 bg-yellow-600 hover:bg-yellow-700 text-white rounded-lg font-medium"
   245→              >
   246→                Got It!
   247→              </button>
   248→            </div>
   249→          </div>
   250→        </div>
   251→      )}
   252→
   253→      {/* Dashboard Grid Layout - CSS Grid with column spanning + drag-drop */}
   254→      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
   255→        <SortableContext items={enabledWidgets} strategy={verticalListSortingStrategy}>
   256→          {enabledWidgets.length > 0 ? (
   257→            <div className="dashboard-grid grid grid-cols-1 md:grid-cols-2 gap-6 auto-rows-min" style={{ gridAutoFlow: 'dense' }}>
   258→              {enabledWidgets.map((widgetId) => {
   259→                // Handle dynamic widget instances (e.g., github-1, github-2)
   260→                const baseWidgetType = widgetId.includes('-') && widgetId.match(/^([a-z]+)-\d+$/)
   261→                  ? widgetId.split('-')[0]
   262→                  : widgetId;
   263→
   264→                const WidgetComponent = WIDGET_COMPONENTS[baseWidgetType];
   265→                if (!WidgetComponent) return null;
   266→
   267→                // Pass widgetId prop for dynamic instances
   268→                const isDynamicInstance = widgetId !== baseWidgetType;
   269→
   270→                // Get widget size (default to 1x)
   271→                // In 2-column grid: 1x = 1 column (50%), 2x = 2 columns (100%), 3x = 2 columns (100%)
   272→                const size = widgetSizes[widgetId] || 1;
   273→                const sizeClass = size >= 2 ? 'md:col-span-2' : '';
   274→
   275→                return (
   276→                  <SortableWidget key={widgetId} id={widgetId} className={sizeClass}>
   277→                    <Suspense fallback={<WidgetLoader />}>
   278→                      {isDynamicInstance ? (
   279→                        <WidgetComponent widgetId={widgetId} />
   280→                      ) : (
   281→                        <WidgetComponent />
   282→                      )}
   283→                    </Suspense>
   284→                  </SortableWidget>
   285→                );
   286→              })}
