const YouTubeWidget = lazy(() => import('../widgets/Dashboard/YouTubeWidget').then(m => ({ default: m.YouTubeWidget })));
const AnalyticsWidget = lazy(() => import('../widgets/Dashboard/AnalyticsWidget').then(m => ({ default: m.AnalyticsWidget })));
const ClipboardWidget = lazy(() => import('../widgets/Dashboard/ClipboardWidget').then(m => ({ default: m.ClipboardWidget })));
const TabManagerWidget = lazy(() => import('../widgets/Dashboard/TabManagerWidget').then(m => ({ default: m.TabManagerWidget })));
const UptimeWidget = lazy(() => import('../widgets/Dashboard/UptimeWidget').then(m => ({ default: m.UptimeWidget })));

// Loading fallback
const WidgetLoader = () => (
  <div className="h-64 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg animate-pulse"></div>
);

// Widget props interface for dynamic instances
interface WidgetProps {
  widgetId?: string;
}

// Widget component mapper
const WIDGET_COMPONENTS: Record<string, React.LazyExoticComponent<React.FC<WidgetProps>>> = {
  // Core widgets
  tasksquickadd: TasksQuickAddWidget,
  upcomingevents: UpcomingEventsWidget,
  recentnotes: RecentNotesWidget,
  // API widgets
  quote: QuoteWidget,
  crypto: CryptoWidget,
  hackernews: HackerNewsWidget,
  facts: FactsWidget,
  github: GitHubWidget,
  joke: JokeWidget,
  pomodoro: PomodoroWidget,
  unsplash: UnsplashWidget,
  reddit: RedditWidget,
  devto: DevToWidget,
  wordofday: WordOfDayWidget,
  currency: CurrencyWidget,
  worldclock: WorldClockWidget,
  ipinfo: IPInfoWidget,
  qrcode: QRCodeWidget,
  colorpalette: ColorPaletteWidget,
  calculator: CalculatorWidget,
  unitconverter: UnitConverterWidget,
  countdown: CountdownWidget,
  shortcuts: ShortcutsWidget,
  stockmarket: StockMarketWidget,
  wikipedia: WikipediaWidget,
  // Phase 2 widgets
  bored: BoredWidget,
  dictionary: DictionaryWidget,
  // REMOVED: producthunt (see WidgetRegistry for details)
  ainews: AINewsWidget,
  airquality: AirQualityWidget,
  packagestats: PackageStatsWidget,
  // Phase 3 widgets
  pixelart: PixelArtWidget,
  typingtest: TypingTestWidget,
  memorygame: MemoryGameWidget,
  motivational: MotivationalWidget,
  githubtrending: GitHubTrendingWidget,
  awesomelists: AwesomeListsWidget,
  repostats: RepoStatsWidget,
  sports: SportsWidget,
  twitch: TwitchWidget,
  youtube: YouTubeWidget,
  analytics: AnalyticsWidget,
  clipboard: ClipboardWidget,
  tabmanager: TabManagerWidget,
  uptime: UptimeWidget,
  // Visual widgets
  weathermap: WeatherMapWidget,
};

/**
 * Dashboard Page - Personal overview
 */
export const Dashboard: React.FC = () => {
  const [hasData, setHasData] = useState(true);
  const [showBackupReminder, setShowBackupReminder] = useState(false);
  const [showWidgetManager, setShowWidgetManager] = useState(false);
  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);

  // Configure drag sensors (require 5px movement to prevent accidental drags)
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 5,
      },
    })
  );

  // Handle drag end - reorder widgets
  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;

    if (over && active.id !== over.id) {
      const oldIndex = enabledWidgets.indexOf(active.id as string);
      const newIndex = enabledWidgets.indexOf(over.id as string);

      if (oldIndex !== -1 && newIndex !== -1) {
        const newOrder = [...enabledWidgets];
        const [movedItem] = newOrder.splice(oldIndex, 1);
        newOrder.splice(newIndex, 0, movedItem);
        reorderWidgets(newOrder);
      }
    }
  };

  useEffect(() => {
    document.title = 'Neuman Brain';

    // Check for hash navigation (#customize-widgets)
    if (window.location.hash === '#customize-widgets') {
      setShowWidgetManager(true);
      // Clear the hash
      window.history.replaceState(null, '', window.location.pathname);
    }

    // Check if user has any data
    const checkForData = async () => {
      try {
        const keys = await indexedDBService.getAllKeys();
        const hasAnyData = keys.length > 0;
        setHasData(hasAnyData);

        // Show backup reminder if no data AND not dismissed
        const dismissed = localStorage.getItem('dashboard-backup-reminder-dismissed');
        if (!hasAnyData && !dismissed) {
          setShowBackupReminder(true);
        }
      } catch (error) {
        console.error('Failed to check for data:', error);
      }
    };

    checkForData();
  }, []);

  const handleDismissReminder = () => {
    setShowBackupReminder(false);
    localStorage.setItem('dashboard-backup-reminder-dismissed', 'true');
  };

  return (
    <div className="dashboard-page">
      <div className="mb-8">
        <h1 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
          Dashboard
        </h1>
        <p className="text-base text-text-light-secondary dark:text-text-dark-secondary">
          Your personal management overview
        </p>
      </div>

      {/* First-Time User Backup Reminder */}
      {showBackupReminder && !hasData && (
        <div className="mb-6 p-6 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-400 dark:border-yellow-600">
          <div className="flex items-start gap-4">
            <span className="text-3xl">⚠️</span>
            <div className="flex-1">
              <h3 className="text-xl font-bold text-yellow-900 dark:text-yellow-300 mb-2">
                Welcome to Neuman Brain!
              </h3>
              <p className="text-sm text-yellow-800 dark:text-yellow-400 mb-3">
                <strong>Important:</strong> Your data is stored locally in this browser. To protect your work, remember to create regular backups!
              </p>
              <div className="bg-white dark:bg-surface-dark-elevated p-4 rounded-lg mb-4">
                <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
                  Quick Start:
                </p>
                <ol className="text-sm text-text-light-secondary dark:text-text-dark-secondary space-y-1 list-decimal list-inside ml-2">
                  <li>Start creating tasks, notes, and plans</li>
                  <li>When you have data to protect, go to Settings → Backup</li>
                  <li>Export your first backup (Chrome/Edge: enable Auto-Save!)</li>
                  <li>Store your .brain file somewhere safe (cloud, USB, etc.)</li>
                </ol>
              </div>
              <button
                onClick={handleDismissReminder}
                className="px-4 py-2 bg-yellow-600 hover:bg-yellow-700 text-white rounded-lg font-medium"
              >
                Got It!
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Dashboard Grid Layout - CSS Grid with column spanning + drag-drop */}
      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <SortableContext items={enabledWidgets} strategy={verticalListSortingStrategy}>
          {enabledWidgets.length > 0 ? (
            <div className="dashboard-grid grid grid-cols-1 md:grid-cols-2 gap-6 auto-rows-min" style={{ gridAutoFlow: 'dense' }}>
              {enabledWidgets.map((widgetId) => {
                // Handle dynamic widget instances (e.g., github-1, github-2)
                const baseWidgetType = widgetId.includes('-') && widgetId.match(/^([a-z]+)-\d+$/)
                  ? widgetId.split('-')[0]
                  : widgetId;

                const WidgetComponent = WIDGET_COMPONENTS[baseWidgetType];
                if (!WidgetComponent) return null;

                // Pass widgetId prop for dynamic instances
                const isDynamicInstance = widgetId !== baseWidgetType;

                // Get widget size (default to 1x)
                // In 2-column grid: 1x = 1 column (50%), 2x = 2 columns (100%), 3x = 2 columns (100%)
                const size = widgetSizes[widgetId] || 1;
                const sizeClass = size >= 2 ? 'md:col-span-2' : '';

                return (
                  <SortableWidget key={widgetId} id={widgetId} className={sizeClass}>
                    <Suspense fallback={<WidgetLoader />}>
                      {isDynamicInstance ? (
                        <WidgetComponent widgetId={widgetId} />
                      ) : (
                        <WidgetComponent />
                      )}
                    </Suspense>
                  </SortableWidget>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
              <p className="text-lg mb-4">No widgets enabled.</p>
              <p className="text-sm">
                Click the ⚙ icon next to "Dashboard" in the sidebar to customize widgets.
              </p>
            </div>
          )}
        </SortableContext>
      </DndContext>

      {/* Widget Manager Modal */}
      <WidgetManager isOpen={showWidgetManager} onClose={() => setShowWidgetManager(false)} />
    </div>
  );
};

