/**
 * IndexedDB Service - Unlimited Local Storage
 *
 * Provides a localStorage-like interface with IndexedDB backend
 * Benefits:
 * - 50GB+ storage capacity (vs 5-10MB localStorage)
 * - Handles large data (images, rich text, etc.)
 * - Async operations for better performance
 * - Automatic versioning and migrations
 */

const DB_NAME = 'neuman-brain-db';
const DB_VERSION = 1;
const STORE_NAME = 'brain-data';

interface DBConnection {
  db: IDBDatabase | null;
  isReady: boolean;
}

class IndexedDBService {
  private connection: DBConnection = {
    db: null,
    isReady: false,
  };

  /**
   * Initialize IndexedDB connection
   */
  async init(): Promise<void> {
    if (this.connection.isReady) {
      return;
    }

    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => {
        console.error('Failed to open IndexedDB:', request.error);
        reject(request.error);
      };

      request.onsuccess = () => {
        this.connection.db = request.result;
        this.connection.isReady = true;
        console.log('✅ IndexedDB initialized');
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        // Create object store if it doesn't exist
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME);
          console.log('📦 Created IndexedDB object store');
        }
      };
    });
  }

  /**
   * Get item from IndexedDB
   */
  async getItem(key: string): Promise<string | null> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.get(key);

      request.onsuccess = () => {
        resolve(request.result ?? null);
      };

      request.onerror = () => {
        console.error(`Failed to get ${key} from IndexedDB:`, request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Set item in IndexedDB
   */
  async setItem(key: string, value: string): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(value, key);

      request.onsuccess = () => {
        resolve();
      };

      request.onerror = () => {
        console.error(`Failed to set ${key} in IndexedDB:`, request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Remove item from IndexedDB
   */
  async removeItem(key: string): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.delete(key);

      request.onsuccess = () => {
        resolve();
      };

      request.onerror = () => {
        console.error(`Failed to remove ${key} from IndexedDB:`, request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Get all keys from IndexedDB
   */
  async getAllKeys(): Promise<string[]> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAllKeys();

      request.onsuccess = () => {
        resolve(request.result as string[]);
      };

      request.onerror = () => {
        console.error('Failed to get all keys from IndexedDB:', request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Get all data from IndexedDB
   */
  async getAllData(): Promise<Record<string, string>> {
    await this.init();

    const keys = await this.getAllKeys();
    const data: Record<string, string> = {};

    for (const key of keys) {
      const value = await this.getItem(key);
      if (value !== null) {
        data[key] = value;
      }
    }

    return data;
  }

  /**
   * Clear all data from IndexedDB
   */
  async clear(): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.clear();

      request.onsuccess = () => {
        console.log('🗑️ Cleared all IndexedDB data');
        resolve();
      };

      request.onerror = () => {
        console.error('Failed to clear IndexedDB:', request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Get storage quota information
   */
  async getQuota(): Promise<{
    usage: number;
    quota: number;
    percentUsed: number;
    available: number;
    usageFormatted: string;
    quotaFormatted: string;
    availableFormatted: string;
  }> {
    if ('storage' in navigator && 'estimate' in navigator.storage) {
      const estimate = await navigator.storage.estimate();
      const usage = estimate.usage || 0;
      const quota = estimate.quota || 0;
      const percentUsed = quota > 0 ? (usage / quota) * 100 : 0;
      const available = quota - usage;

      return {
        usage,
        quota,
        percentUsed,
        available,
        usageFormatted: this.formatBytes(usage),
        quotaFormatted: this.formatBytes(quota),
        availableFormatted: this.formatBytes(available),
      };
    }

    // Fallback for browsers without Storage API
    return {
      usage: 0,
      quota: 0,
      percentUsed: 0,
      available: 0,
      usageFormatted: '0 Bytes',
      quotaFormatted: '0 Bytes',
      availableFormatted: '0 Bytes',
    };
  }

  /**
   * Format bytes to human-readable string
   */
  formatBytes(bytes: number): string {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${Math.round((bytes / Math.pow(k, i)) * 100) / 100} ${sizes[i]}`;
  }

  /**
   * Check if storage is getting full (>80%)
   */
  async isStorageNearlyFull(): Promise<boolean> {
    const quota = await this.getQuota();
    return quota.percentUsed > 80;
  }

  /**
   * Check if IndexedDB is supported
   */
  isSupported(): boolean {
    return typeof indexedDB !== 'undefined';
  }

  /**
   * Store an object (structured clone) in IndexedDB
   * Useful for storing FileSystemDirectoryHandle and other complex objects
   */
  async setObject(key: string, value: any): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(value, key);

      request.onsuccess = () => {
        resolve();
      };

      request.onerror = () => {
        console.error(`Failed to set object ${key} in IndexedDB:`, request.error);
        reject(request.error);
      };
    });
  }

  /**
   * Retrieve an object from IndexedDB
   */
  async getObject<T = any>(key: string): Promise<T | null> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.get(key);

      request.onsuccess = () => {
        resolve(request.result ?? null);
      };

      request.onerror = () => {
        console.error(`Failed to get object ${key} from IndexedDB:`, request.error);
        reject(request.error);
      };
    });
  }
}

// Export singleton instance
export const indexedDBService = new IndexedDBService();

