    31→  onDelete: (id: string, name: string) => void;
    32→  onRename: (id: string, name: string) => void;
    33→  getFolderNoteCount: (id: string) => number;
    34→}
    35→
    36→const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
    37→  node,
    38→  depth,
    39→  activeFolderId,
    40→  expandedFolderIds,
    41→  onSelect,
    42→  onToggleExpanded,
    43→  onDelete,
    44→  onRename,
    45→  getFolderNoteCount,
    46→}) => {
    47→  const isExpanded = expandedFolderIds.has(node.id);
    48→  const hasChildren = node.children && node.children.length > 0;
    49→  const noteCount = getFolderNoteCount(node.id);
    50→
    51→  return (
    52→    <div>
    53→      <div
    54→        className={`group relative rounded-lg transition-colors ${
    55→          activeFolderId === node.id
    56→            ? 'bg-primary-cyan bg-opacity-10'
    57→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
    58→        }`}
    59→        style={{ paddingLeft: `${depth * 16}px` }}
    60→      >
    61→        <div className="flex items-center">
    62→          {/* Expand/collapse button */}
    63→          {hasChildren && (
    64→            <button
    65→              onClick={(e) => {
    66→                e.stopPropagation();
    67→                onToggleExpanded(node.id);
    68→              }}
    69→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
    70→            >
    71→              <span className="text-sm">{isExpanded ? '▼' : '▶'}</span>
    72→            </button>
    73→          )}
    74→          {!hasChildren && <span className="w-6" />}
    75→
    76→          {/* Folder button */}
    77→          <button
    78→            onClick={() => onSelect(node.id)}
    79→            className={`flex-1 text-left px-3 py-2 transition-colors flex items-center gap-2 ${
    80→              activeFolderId === node.id
    81→                ? 'text-primary-cyan font-medium'
    82→                : 'text-text-light-secondary dark:text-text-dark-secondary'
    83→            }`}
    84→          >
    85→            <span>{hasChildren ? (isExpanded ? '📂' : '📁') : '📄'}</span>
    86→            <span>{node.name}</span>
    87→            {noteCount > 0 && (
    88→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
    89→                ({noteCount})
    90→              </span>
    91→            )}
    92→          </button>
    93→
    94→          {/* Action buttons */}
    95→          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
    96→            <button
    97→              onClick={(e) => {
    98→                e.stopPropagation();
    99→                onRename(node.id, node.name);
   100→              }}
   101→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   102→              title="Rename folder"
   103→            >
   104→              ✏️
   105→            </button>
   106→            <button
   107→              onClick={(e) => {
   108→                e.stopPropagation();
   109→                onDelete(node.id, node.name);
   110→              }}
   111→              className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-colors"
   112→              title="Delete folder"
   113→            >
   114→              🗑️
   115→            </button>
   116→          </div>
   117→        </div>
   118→      </div>
   119→
   120→      {/* Children */}
   121→      {isExpanded && hasChildren && (
   122→        <div className="ml-4">
   123→          {node.children.map((child: any) => (
   124→            <FolderTreeNode
   125→              key={child.id}
   126→              node={child}
   127→              depth={depth + 1}
   128→              activeFolderId={activeFolderId}
   129→              expandedFolderIds={expandedFolderIds}
   130→              onSelect={onSelect}
   131→              onToggleExpanded={onToggleExpanded}
   132→              onDelete={onDelete}
   133→              onRename={onRename}
   134→              getFolderNoteCount={getFolderNoteCount}
   135→            />
   136→          ))}
   137→        </div>
   138→      )}
