   149→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   150→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   151→  const createFolder = useFoldersStore((state) => state.createFolder);
   152→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   153→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   154→  const notesObj = useNotesStore((state) => state.notes);
   155→  const searchNotes = useNotesStore((state) => state.searchNotes);
   156→
   157→  // Dialog state
   158→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   159→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   160→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   161→  const [selectedFolderName, setSelectedFolderName] = useState('');
   162→
   163→  // Search state
   164→  const [searchQuery, setSearchQuery] = useState('');
   165→  const searchInputRef = useRef<HTMLInputElement>(null);
   166→
   167→  // Keyboard shortcut for search (Cmd+K)
   168→  useEffect(() => {
   169→    const handleKeyDown = (e: KeyboardEvent) => {
   170→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   171→        e.preventDefault();
   172→        searchInputRef.current?.focus();
   173→      }
   174→    };
   175→
   176→    window.addEventListener('keydown', handleKeyDown);
   177→    return () => window.removeEventListener('keydown', handleKeyDown);
   178→  }, []);
   179→
   180→  // Get tree structure for nested folders
