   209→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   210→    const noteCount = notesToDelete.length;
   211→
   212→    // Delete all notes in this folder (without undo since folder undo will handle it)
   213→    // We need to temporarily bypass the undo system for individual notes
   214→    notesToDelete.forEach(note => {
   215→      // Call the store action directly without triggering undo
   216→      useNotesStore.setState((state) => {
   217→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   218→        return {
   219→          notes: remainingNotes,
   220→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   221→        };
   222→      });
   223→    });
   224→
   225→    // Delete the folder
   226→    deleteFolder(selectedFolderId);
   227→
   228→    console.log(`✅ Folder "${folderToDelete.name}" deleted with ${noteCount} note(s)`);
   229→
   230→    // Add undo action to restore folder AND notes
   231→    useUndoStore.getState().addUndoAction(
   232→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   233→      () => {
   234→        // Restore the folder
