   236→          folders: {
   237→            ...state.folders,
   238→            [folderToDelete.id]: folderToDelete,
   239→          },
   240→        }));
   241→
   242→        // Restore all notes
   243→        useNotesStore.setState((state) => {
   244→          const restoredNotes = { ...state.notes };
   245→          notesToDelete.forEach(note => {
   246→            restoredNotes[note.id] = note;
   247→          });
   248→          return {
   249→            notes: restoredNotes,
   250→          };
   251→        });
   252→
   253→        console.log(`✅ Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   254→      }
   255→    );
   256→  };
   257→
   258→  // Handle folder rename
   259→  const handleRenameFolder = (folderId: string, currentName: string) => {
