   270→  return (
   271→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   272→      {/* Folders header */}
   273→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   274→        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
   275→        <button
   276→          onClick={() => createFolder()}
   277→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   278→          title="New Folder"
   279→        >
   280→          + Folder
   281→        </button>
   282→      </div>
   283→
   284→      {/* Search Input */}
   285→      <div className="px-3 py-2">
   286→        <input
   287→          type="text"
   288→          placeholder="Search notes... (Cmd+K)"
   289→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   290→                     bg-surface-light dark:bg-surface-dark
   291→                     text-text-light-primary dark:text-text-dark-primary
   292→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
