   299→
   300→      {/* All Notes (root level) */}
   301→      {!searchQuery.trim() && (
   302→        <button
   303→          onClick={() => setActiveFolder(null)}
   304→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center text-base ${
   305→            activeFolderId === null
   306→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   307→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   308→          }`}
