   417→    const diff = now.getTime() - new Date(date).getTime();
   418→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   419→
   420→    if (days === 0) return 'Today';
   421→    if (days === 1) return 'Yesterday';
   422→    if (days < 7) return `${days} days ago`;
   423→    return new Date(date).toLocaleDateString();
   424→  };
   425→
   426→  // First line of content
   427→  const preview = note.contentText.split('\n')[0] || 'No content';
   428→
   429→  return (
   430→    <div
   431→      className={`group relative p-3 rounded-lg cursor-pointer transition-all ${
