   450→        {preview}
   451→      </p>
   452→
   453→      {/* Meta */}
   454→      <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
   455→        <span>{formatDate(note.updatedAt)}</span>
   456→        {note.tags.length > 0 && (
   457→          <span className="truncate ml-2">🏷️ {note.tags[0]}</span>
   458→        )}
   459→      </div>
   460→
   461→      {/* Actions (show on hover) */}
   462→      <div className="absolute top-2 right-8 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
   463→        <button
   464→          onClick={(e) => {
