   513→/**
   514→ * Notes List Component
   515→ */
   516→const NotesList: React.FC = () => {
   517→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   518→  // Get raw notes and store config (stable references)
   519→  const notesObj = useNotesStore((state) => state.notes);
   520→  const sortConfig = useNotesStore((state) => state.sortConfig);
   521→  const filter = useNotesStore((state) => state.filter);
   522→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   523→  const createNote = useNotesStore((state) => state.createNote);
   524→
   525→  // Compute filtered/sorted notes with useMemo
   526→  const notes = useMemo(() => {
   527→    // Filter by folder
   528→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   529→    let filtered = activeFolderId === null
   530→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   531→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   532→
   533→    // Apply filter (archived, pinned, etc.)
   534→    switch (filter) {
   535→      case 'pinned':
   536→        filtered = filtered.filter((note) => note.isPinned);
   537→        break;
   538→      case 'archived':
   539→        filtered = filtered.filter((note) => note.isArchived);
   540→        break;
   541→      case 'unarchived':
   542→        filtered = filtered.filter((note) => !note.isArchived);
   543→        break;
   544→    }
   545→
   546→    // Sort notes
   547→    const sorted = [...filtered].sort((a, b) => {
   548→      let comparison = 0;
   549→      switch (sortConfig.field) {
   550→        case 'title':
   551→          comparison = a.title.localeCompare(b.title);
   552→          break;
   553→        case 'createdAt':
   554→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   555→          break;
   556→        case 'updatedAt':
   557→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   558→          break;
   559→      }
   560→      return sortConfig.order === 'asc' ? comparison : -comparison;
   561→    });
   562→
   563→    // Always pin pinned notes to top
   564→    return sorted.sort((a, b) => {
   565→      if (a.isPinned && !b.isPinned) return -1;
   566→      if (!a.isPinned && b.isPinned) return 1;
   567→      return 0;
   568→    });
   569→  }, [notesObj, activeFolderId, sortConfig, filter]);
   570→
   571→  return (
   572→    <div className="flex-1 overflow-y-auto">
   573→      <div className="bento-card p-4 m-3">
   574→        {/* Notes header */}
   575→        <div className="flex items-center justify-between mb-4">
   576→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   577→            Notes ({notes.length})
   578→          </h3>
   579→          <button
   580→            onClick={() => createNote({ folderId: activeFolderId })}
   581→            className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   582→          >
   583→            + New Note
   584→          </button>
   585→        </div>
   586→
   587→      {/* Notes list */}
   588→      <div className="space-y-2">
   589→        {notes.map((note) => (
   590→          <NoteListItem
   591→            key={note.id}
   592→            note={note}
   593→            isActive={note.id === activeNoteId}
   594→          />
   595→        ))}
   596→      </div>
   597→
   598→      {/* Empty state */}
